    10→type BuiltinFn = (args: Value[], vm: VM) => Value;
    11→type Frame = { retAddr: number; baseSlot: number; fn: string; upvalues: Value[]; capabilities: Array<{cap: string; arg?: string}> };
    12→type TryHandler = { catchAddr: number; stackDepth: number; frameDepth: number };
    13→type LoopContext = {
    14→  addr: number;
    15→  iterationCount: number;
    16→  // Phase 3.8: State snapshot for memory isolation
    17→  stackHeightAtEntry: number;
    18→  globalSnapshotAtEntry: Map<string, Value>;
    19→  localSnapshotAtEntry: Value[];
    20→  stateChanges: { varName: string; before: Value; after: Value }[];
    21→};
    22→
    23→export class VM {
    24→  private stack: Value[] = [];
    25→  private globals = new Map<string, Value>();
    26→  private frames: Frame[] = [];
    27→  private tryStack: TryHandler[] = [];
    28→  private ip = 0;
    29→  private output: string[] = [];
    30→  private builtinFns: Record<string, BuiltinFn>;
    31→  // Phase 8: try/catch error handling
    32→  private lastError: Value | null = null;
    33→  private inTryCall = false;
    34→  // Phase 3.7: Safety guard & iteration tracking
    35→  // Phase 3.9: Jump Table & Offset Optimization
    36→  private jumpTable: JumpTable;
    37→  private offsetCalc: OffsetCalculator = new OffsetCalculator();
    38→  // Phase 5.9: Dynamic Memory Allocator
    39→  private memoryAllocator: MemoryAllocator = new MemoryAllocator();
    40→  // STEP 1: HeapManager (v6 재설계)
    41→  private heapManager: HeapManager = new HeapManager();
    42→  // Phase 4: Unsafe 격리 레이어
    43→  private unsafeManager: UnsafeManager = new UnsafeManager();
    44→  private currentUnsafeZone: number = -1;
    45→  private unsafeDepth: number = 0;
    46→
    47→  // Phase 6: Built-in capability requirements
    48→  private readonly BUILTIN_REQUIRED_CAPABILITIES = new Map<string, string>([
    49→    ["file_read", "read_file"],
    50→    ["file_write", "write_file"],
    51→    ["http_request", "network"],
    52→    ["http_get", "network"],
    53→    ["process_spawn", "spawn_process"],
    54→    ["eval", "execute_code"],
    55→  ]);
    56→
    57→  private traceMode = false;
    58→  private traceLogs: string[] = [];
    59→  private loopStack: LoopContext[] = [];  // Track loop start positions + iteration counts
    60→  private loopDepth = 0;                   // Track nesting depth
    61→  private readonly MAX_SAFE_ITERATIONS = 1_000_000;  // Safety guard limit
    62→
    63→  constructor(private chunk: Chunk, initialGlobals?: Map<string, Value>) {
    64→    this.builtinFns = getBuiltins();
    65→    this.jumpTable = new JumpTable(this.loopStack);
    66→
    67→    // Register builtins
    68→    for (const name of Object.keys(this.builtinFns)) {
    69→      this.globals.set(name, { tag: "builtin", name });
    70→    }
    71→    // Restore persisted globals (e.g. from REPL)
    72→    if (initialGlobals) {
    73→      for (const [k, v] of initialGlobals) {
    74→        if (!this.globals.has(k)) this.globals.set(k, v);
    75→      }
    76→    }
    77→
    78→    // PHASE 3: HeapManager에 Root Collector 콜백 등록
    79→    this.heapManager.setRootCollector(() => this.getRoots());
    80→  }
    81→
    82→  getGlobals(): Map<string, Value> { return new Map(this.globals); }
