    84→  // Phase 6: Check if current function has required capability for builtin
    85→  private checkBuiltinCapability(builtinName: string): void {
    86→    const required = this.BUILTIN_REQUIRED_CAPABILITIES.get(builtinName);
    87→    if (!required) return; // Safe builtins (print, len, etc) pass through
