     8→/**
     9→ * 테스트 헬퍼 함수
    10→ */
    11→function run(code: string): string {
    12→  try {
    13→    const tokens = lex(code);
    14→    const program = parse(tokens);
    15→    const chunk = compile(program);
    16→    const vm = new VM(chunk);
    17→    const { output } = vm.run();
    18→    return output.join("");
    19→  } catch (e) {
    20→    if (e instanceof Error) {
    21→      return `ERROR: ${e.message}`;
    22→    }
    23→    return `ERROR: ${e}`;
    24→  }
    25→}
