    34→  } catch (e) {
    35→    console.log(`✗ ${name}`);
    36→    if (e instanceof Error) {
    37→      console.log(`  Error: ${e.message}`);
    38→    }
    39→  }
    40→}
    41→
    42→function assert(condition: boolean, message: string) {
    43→  if (!condition) {
    44→    throw new Error(message);
    45→  }
    46→}
    47→
    48→function assertEqual(actual: any, expected: any, message: string) {
    49→  if (actual !== expected) {
    50→    throw new Error(`${message}: expected "${expected}", got "${actual}"`);
    51→  }
    52→}
    53→
    54→function assertContains(actual: string, substring: string, message: string) {
    55→  if (!actual.includes(substring)) {
    56→    throw new Error(`${message}: expected to contain "${substring}", got "${actual}"`);
    57→  }
