   100→  // Phase 6: Get capabilities from current frame
   101→  private getCurrentCapabilities(): Array<{cap: string; arg?: string}> {
   102→    if (this.frames.length === 0) return [];
   103→    return this.frames[this.frames.length - 1].capabilities;
   104→  }
   105→
   106→  run(): { output: string[]; result: Value } {
   107→    while (this.ip < this.chunk.code.length) {
   108→      const op = this.chunk.code[this.ip++];
   109→      if (op === Op.Halt) {
   110→        return { output: this.output, result: this.stack.length > 0 ? this.peek() : { tag: "null" } };
   111→      }
   112→      try {
   113→        this.execOp(op);
   114→      } catch (e) {
   115→        // If error was caught by a try handler
   116→        if (e instanceof Error && e.message.startsWith("__FREELANG_ERROR_CAUGHT__")) {
   117→          // Continue from the new IP (which should point to catch handler or finally)
   118→          continue;
   119→        }
   120→        // Re-throw unhandled errors
   121→        throw e;
   122→      }
   123→    }
   124→    return { output: this.output, result: { tag: "null" } };
   125→  }
   126→
   127→  // Public API for builtins
   128→  getGlobal(name: string): Value | undefined { return this.globals.get(name); }
   129→  setGlobal(name: string, val: Value) { this.globals.set(name, val); }
   130→  getOutput(): string[] { return this.output; }
   131→  addOutput(s: string) { this.output.push(s); }
   132→  getLastError(): Value | null { return this.lastError; }
   133→  clearLastError() { this.lastError = null; }
   134→
   135→  // Phase 5.9: Memory Allocator API for builtins
   136→  getAllocator() { return this.memoryAllocator; }
   137→
   138→  // PHASE 3: GC Root Collection
   139→  /**
   140→   * Stack, Globals, Frames에서 모든 포인터 수집 (GC Root)
   141→   */
   142→  private getRoots(): number[] {
   143→    const roots: number[] = [];
   144→
   145→    // 1. Stack의 모든 포인터 수집
   146→    this.stack.forEach(val => {
   147→      if (val.tag === "ptr") {
   148→        roots.push(val.addr);
   149→      }
   150→    });
   151→
   152→    // 2. Globals의 모든 포인터 수집
   153→    this.globals.forEach(val => {
   154→      if (val.tag === "ptr") {
   155→        roots.push(val.addr);
   156→      }
   157→    });
   158→
   159→    // 3. Frames의 upvalues 포인터 수집
   160→    this.frames.forEach(frame => {
   161→      frame.upvalues.forEach(val => {
   162→        if (val.tag === "ptr") {
   163→          roots.push(val.addr);
   164→        }
   165→      });
   166→    });
   167→
   168→    return roots;
   169→  }
   170→
   171→  // Trace mode for PC debugging
   172→  enableTrace() { this.traceMode = true; this.traceLogs = []; }
   173→  getTraceLogs(): string[] { return this.traceLogs; }
   174→
   175→  /** Call a FreeLang fn or builtin Value from within a builtin (HOFs). */
   176→  callValue(callee: Value, args: Value[]): Value {
   177→    if (callee.tag === "builtin") {
   178→      return this.builtinFns[callee.name](args, this);
   179→    }
   180→    if (callee.tag === "fn") {
   181→      const savedIp = this.ip;
   182→      const targetFrameDepth = this.frames.length;
   183→
   184→      // Mimic Call opcode: push callee + args, push frame
   185→      this.stack.push(callee);
   186→      for (const a of args) this.stack.push(a);
   187→      this.frames.push({
   188→        retAddr: savedIp,
   189→        baseSlot: this.stack.length - args.length,
   190→        fn: callee.name,
   191→        upvalues: callee.freeVars,
   192→        capabilities: callee.capabilities || [],  // Phase 6: Pass capabilities
   193→      });
   194→      this.ip = callee.addr;
   195→
   196→      // Execute until our frame is popped by Return
   197→      try {
   198→        while (this.frames.length > targetFrameDepth) {
   199→          const op = this.chunk.code[this.ip++];
   200→          this.execOp(op);
   201→        }
   202→      } catch (e) {
   203→        // Re-throw sentinel errors so try_call can catch them
   204→        if (e instanceof Error && e.message === "__FREELANG_ERROR_CAUGHT__") {
   205→          throw e;
   206→        }
   207→        // Re-throw other errors
   208→        throw e;
   209→      }
   210→      // Return handler pushed the result onto the stack and restored ip
   211→      return this.stack.pop()!;
   212→    }
   213→    throw new Error(`Cannot call ${callee.tag}`);
   214→  }
   215→
   216→  /** Safe call for try_call builtin - captures errors as Value objects */
   217→  trySafeCall(callee: Value, args: Value[]): { ok: boolean; value?: Value; error?: Value } {
   218→    this.clearLastError();
   219→    this.inTryCall = true;
   220→
   221→    try {
   222→      if (callee.tag === "builtin") {
   223→        const retVal = this.builtinFns[callee.name](args, this);
   224→        return { ok: true, value: retVal };
   225→      }
   226→      if (callee.tag === "fn") {
   227→        const retVal = this.callValue(callee, args);
   228→        return { ok: true, value: retVal };
   229→      }
   230→      return { ok: false, error: { tag: "str", val: `Cannot call ${callee.tag}` } };
   231→    } catch (e) {
   232→      // Check if a FreeLang error occurred
   233→      if (e instanceof Error && e.message.startsWith("__FREELANG_ERROR_CAUGHT__")) {
   234→        // Return the last error that was caught
   235→        return { ok: false, error: this.lastError || { tag: "str", val: "Unknown error" } };
   236→      }
   237→      // Otherwise return string error
   238→      return { ok: false, error: { tag: "str", val: String(e) } };
   239→    } finally {
   240→      this.inTryCall = false;
   241→    }
   242→  }
