     1→// FreeLang v6: Built-in Functions Registry
     2→
     3→import { Value } from "../compiler";
     4→import { VM } from "../vm";
     5→
     6→type BuiltinFn = (args: Value[], vm: VM) => Value;
     7→
     8→const builtins: Record<string, BuiltinFn> = {};
     9→
    10→export function registerBuiltin(name: string, fn: BuiltinFn) {
    11→  builtins[name] = fn;
    12→}
    13→
