   785→// Helper for value equality check
   786→function valEq(a: Value, b: Value): boolean {
   787→  if (a.tag !== b.tag) return false;
   788→  if (a.tag === "null") return true;
   789→  if (a.tag === "num" || a.tag === "str" || a.tag === "bool") return (a as any).val === (b as any).val;
   790→  return a === b;
   791→}
