   793→// Helpers
   794→function numVal(v: Value): number { return v.tag === "num" ? v.val : 0; }
   795→function strVal(v: Value): string { return v.tag === "str" ? v.val : String((v as any).val ?? ""); }
   796→function truthy(v: Value): boolean {
   797→  if (v.tag === "null") return false;
   798→  if (v.tag === "bool") return v.val;
   799→  if (v.tag === "num") return v.val !== 0;
   800→  if (v.tag === "str") return v.val !== "";
   801→  return true;
   802→}
