   804→function toJS(v: Value): any {
   805→  switch (v.tag) {
   806→    case "num": case "str": case "bool": return v.val;
   807→    case "null": return null;
   808→    case "array": return v.val.map(toJS);
   809→    case "object": {
   810→      const obj: any = {};
   811→      for (const [k, val] of v.val) obj[k] = toJS(val);
   812→      return obj;
   813→    }
   814→    default: return null;
   815→  }
   816→}
   817→
   818→function fromJS(v: any): Value {
   819→  if (v === null || v === undefined) return { tag: "null" };
   820→  if (typeof v === "number") return { tag: "num", val: v };
   821→  if (typeof v === "string") return { tag: "str", val: v };
   822→  if (typeof v === "boolean") return { tag: "bool", val: v };
   823→  if (Array.isArray(v)) return { tag: "array", val: v.map(fromJS) };
   824→  if (typeof v === "object") {
   825→    const map = new Map<string, Value>();
   826→    for (const [k, val] of Object.entries(v)) map.set(k, fromJS(val));
