  1179→// === Memory Type System ===
  1180→
  1181→// sizeof(type) - Get the size in bytes of a type or struct
  1182→registerBuiltin("sizeof", (args) => {
  1183→  const v = args[0];
  1184→
  1185→  // Handle struct types passed as objects
  1186→  if (v.tag === "object") {
  1187→    // Check if this is a struct (has __struct_name__)
  1188→    const structName = v.val.get("__struct_name__");
  1189→    if (structName && structName.tag === "str") {
  1190→      // It's a struct - calculate size from fields
  1191→      const fieldsStr = v.val.get("__fields__");
  1192→      if (fieldsStr && fieldsStr.tag === "str") {
  1193→        try {
  1194→          const fields: Array<{ name: string; type: string }> = JSON.parse(fieldsStr.val);
  1195→          let totalSize = 0;
  1196→          let maxAlign = 1;
  1197→
  1198→          // Calculate field sizes and track alignment
  1199→          for (const field of fields) {
  1200→            const fieldSize = getTypeSize(field.type);
  1201→            const fieldAlign = getTypeAlign(field.type);
  1202→
  1203→            // Align current offset
  1204→            totalSize = align(totalSize, fieldAlign);
  1205→            totalSize += fieldSize;
  1206→
  1207→            // Track max alignment requirement
  1208→            if (fieldAlign > maxAlign) maxAlign = fieldAlign;
  1209→          }
  1210→
  1211→          // Align final size to max alignment (trailing padding)
  1212→          totalSize = align(totalSize, maxAlign);
  1213→
  1214→          return { tag: "num", val: totalSize };
  1215→        } catch {
  1216→          return { tag: "num", val: 0 };
  1217→        }
  1218→      }
  1219→    }
  1220→    // Generic object size estimate
  1221→    return { tag: "num", val: v.val.size * 16 };
  1222→  }
  1223→
  1224→  // Handle basic types
  1225→  if (v.tag === "num") return { tag: "num", val: 8 };
  1226→  if (v.tag === "str") return { tag: "num", val: 16 };  // pointer + length = 8 + 8
  1227→  if (v.tag === "bool") return { tag: "num", val: 1 };
  1228→  if (v.tag === "null") return { tag: "num", val: 0 };
  1229→  if (v.tag === "array") return { tag: "num", val: 8 + (v.val.length * 8) };
  1230→  if (v.tag === "ptr") return { tag: "num", val: 4 };    // v5.9.1: Pointer size
  1231→
  1232→  return { tag: "num", val: 0 };
  1233→});
  1234→
  1235→// Helper: Get size of a type string (i32, f64, bool, byte, string, etc)
  1236→// v5.9.2: Updated for 4-byte alignment
  1237→function getTypeSize(type: string): number {
  1238→  const t = type.toLowerCase().trim();
  1239→  const sizeMap: Record<string, number> = {
  1240→    "i32": 4,
  1241→    "i64": 8,
  1242→    "f32": 4,
  1243→    "f64": 8,
  1244→    "bool": 1,
  1245→    "byte": 1,
  1246→    "char": 1,
  1247→    "string": 16, // pointer + length
  1248→    "any": 8,
  1249→    "ptr": 4,     // Pointer type (v5.9.1)
  1250→    "null": 0,
  1251→  };
  1252→  return sizeMap[t] || 8; // default to 8
  1253→}
  1254→
  1255→// Helper: Get alignment requirement of a type
  1256→// v5.9.2: Supports 4-byte and 8-byte boundaries
  1257→function getTypeAlign(type: string): number {
  1258→  const t = type.toLowerCase().trim();
  1259→  const alignMap: Record<string, number> = {
  1260→    "i32": 4,
  1261→    "i64": 8,
  1262→    "f32": 4,
  1263→    "f64": 8,
  1264→    "bool": 1,
  1265→    "byte": 1,
  1266→    "char": 1,
  1267→    "string": 4,  // Changed to 4 for v5.9.2
  1268→    "any": 4,     // Changed to 4 for v5.9.2
  1269→    "ptr": 4,     // Pointer alignment (v5.9.1)
  1270→    "null": 1,
  1271→  };
  1272→  return alignMap[t] || 4; // default to 4 for v5.9.2
  1273→}
  1274→
  1275→// Helper: Align offset to next multiple of alignment
  1276→function align(offset: number, alignment: number): number {
  1277→  if (alignment <= 1) return offset;
  1278→  const remainder = offset % alignment;
  1279→  return remainder === 0 ? offset : offset + (alignment - remainder);
  1280→}
