  1282→// === Phase 5.9: Dynamic Memory ===
  1283→
  1284→// malloc(size) - Allocate size bytes and return pointer (address)
  1285→registerBuiltin("malloc", (args, vm) => {
  1286→  const size = numVal(args[0]);
