// args[0] = 파일 경로 (string Value)
// args[1] = 내용 (string Value, file_write만)
registerBuiltin("file_read", (args) => {
  try { return { tag: "str", val: fs.readFileSync(strVal(args[0]), "utf-8") }; }
  catch (e: any) { return { tag: "null" }; }
});
```

